package com.melodyrent.config;
import com.melodyrent.entity.*; import com.melodyrent.repository.*; import lombok.RequiredArgsConstructor; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.Bean; import org.springframework.context.annotation.Configuration; import org.springframework.security.crypto.password.PasswordEncoder; import java.math.BigDecimal; import java.time.LocalDate; import java.util.Set;
@Configuration @RequiredArgsConstructor
public class DataSeeder {
  private final RoleRepository roles; private final UserRepository users; private final CategoryRepository categories; private final ProductRepository products; private final PricingRuleRepository pricingRules; private final PasswordEncoder encoder;
  @Bean CommandLineRunner seed(){ return args -> { for(RoleName r: RoleName.values()) roles.findByName(r).orElseGet(() -> roles.save(Role.builder().name(r).build())); if(categories.count()==0){ categories.save(Category.builder().name("Cars").icon("FaCar").gradient("from-sky-300 to-lavender-400").build()); categories.save(Category.builder().name("Cameras").icon("FaCameraRetro").gradient("from-pink-300 to-purple-400").build()); categories.save(Category.builder().name("Gaming").icon("FaGamepad").gradient("from-mint-300 to-sky-400").build()); } if(users.count()==0){ users.save(User.builder().fullName("Melody Admin").email("admin@melodyrent.local").password(encoder.encode("Password123!")).roles(Set.of(roles.findByName(RoleName.ADMIN).orElseThrow())).build()); var owner=users.save(User.builder().fullName("Luna Owner").email("owner@melodyrent.local").password(encoder.encode("Password123!")).roles(Set.of(roles.findByName(RoleName.OWNER).orElseThrow())).build()); var cat=categories.findAll().get(0); var p=Product.builder().title("Pastel Porsche Weekend Cruiser").description("A dreamy premium car rental with a curated synth-pop playlist.").basePricePerDay(new BigDecimal("189.00")).city("Los Angeles").inventory(1).approved(true).available(true).category(cat).owner(owner).model3dUrl("/models/car.glb").build(); p.getImages().add(ProductImage.builder().url("https://images.unsplash.com/photo-1503376780353-7e6692767b70").product(p).build()); p.getMusicTracks().add(MusicTrack.builder().title("Lavender Drive").artist("MelodyRent Sessions").url("https://res.cloudinary.com/demo/video/upload/sample.mp3").durationSeconds(180).product(p).build()); products.save(p); } if(pricingRules.count()==0) pricingRules.save(PricingRule.builder().name("Summer Peak Season").multiplier(new BigDecimal("1.35")).startsOn(LocalDate.of(2026,6,1)).endsOn(LocalDate.of(2026,8,31)).active(true).build()); }; }
}
